import * as React from 'react';
import type { MyProps } from '../models';
import styles from '../styles/App.module.scss';

export function My(props: MyProps): JSX.Element {
  const { description, isDarkTheme, userDisplayName, environmentMessage } = props;

  return (
    <section className={`${styles.app} ${isDarkTheme ? styles.dark : ''}`}>
      <h2>Welcome, {userDisplayName}!</h2>
      <p>{description}</p>
      <p>{environmentMessage}</p>
    </section>
  );
}